// Calculate cost from token usage
const input = $input.item.json;

// Expected input format:
// {
//   "action": "calculate_cost",
//   "payload": {
//     "provider": "openai",
//     "model": "gpt-4o",
//     "inputTokens": 1000,
//     "outputTokens": 500,
//     "clientId": "client-123",
//     "projectId": "project-456",
//     "workflowId": "workflow-789"
//   }
// }

const payload = input.payload || input;
const provider = payload.provider || 'openai';
const model = payload.model || 'gpt-4o';

// Cost per 1K tokens (as of Dec 2025)
const pricing = {
  openai: {
    'gpt-4o': { input: 0.0025, output: 0.01 },
    'gpt-4-turbo': { input: 0.01, output: 0.03 },
    'gpt-3.5-turbo': { input: 0.0005, output: 0.0015 },
    'whisper-1': { input: 0.006, output: 0 }
  },
  anthropic: {
    'claude-3-5-sonnet': { input: 0.003, output: 0.015 },
    'claude-3-opus': { input: 0.015, output: 0.075 }
  }
};

const providerPricing = pricing[provider] || pricing.openai;
const modelPricing = providerPricing[model] || providerPricing['gpt-4o'];

const inputCost = (payload.inputTokens / 1000) * modelPricing.input;
const outputCost = (payload.outputTokens / 1000) * modelPricing.output;
const totalCost = inputCost + outputCost;

return {
  provider,
  model,
  inputTokens: payload.inputTokens || 0,
  outputTokens: payload.outputTokens || 0,
  inputCost: parseFloat(inputCost.toFixed(6)),
  outputCost: parseFloat(outputCost.toFixed(6)),
  totalCost: parseFloat(totalCost.toFixed(6)),
  clientId: payload.clientId || 'unknown',
  projectId: payload.projectId || 'unknown',
  workflowId: payload.workflowId || 'unknown',
  timestamp: new Date().toISOString(),
  currency: 'USD'
};
